-- DuckDB v1.3.2

CREATE TABLE banks (bank_id INTEGER PRIMARY KEY, bank_name VARCHAR NOT NULL, app_id VARCHAR NOT NULL, known_rating DOUBLE);

CREATE TABLE topics (topic_id INTEGER PRIMARY KEY, topic_name VARCHAR NOT NULL, topic_size INTEGER, keywords VARCHAR);

CREATE TABLE reviews (review_id VARCHAR PRIMARY KEY, bank_id INTEGER REFERENCES banks(bank_id), topic_id INTEGER REFERENCES topics(topic_id), review VARCHAR, rating INTEGER, date DATE, helpful_count INTEGER, language VARCHAR, sentiment_label VARCHAR, sentiment_score DOUBLE, low_confidence BOOLEAN, is_short_review BOOLEAN, developer_replied BOOLEAN, topic_name VARCHAR, topic_prob DOUBLE, source VARCHAR, review_lemma VARCHAR);



